def count_usable_ingredients(T, input_lines):
    count = 0  
    for line in input_lines:
        RA_parts = line.split()  
        if len(RA_parts) != 2:
            continue 
        R = int(RA_parts[0]) 
        A = int(RA_parts[1]) 
        if A >= R:
            count += 1
    return count
